#### **任务 2: API 安全中间件**
**工作量**: 1 天 | **文件**: `src/dashboard/middleware/security.ts`

```bash
# 安装依赖
npm install @fastify/rate-limit @fastify/helmet
```

```typescript
// src/dashboard/middleware/security.ts
import fp from 'fastify-plugin'
import rateLimit from '@fastify/rate-limit'
import helmet from '@fastify/helmet'

export default fp(async (server: any) => {
  // 1. 安全头
  await server.register(helmet, {
    contentSecurityPolicy: {
      directives: {
        defaultSrc: ["'self'"],
        scriptSrc: ["'self'", "'unsafe-inline'"],
        styleSrc: ["'self'", "'unsafe-inline'"],
        imgSrc: ["'self'", 'data:', 'https:']
      }
    },
    hsts: {
      maxAge: 31536000,
      includeSubDomains: true,
      preload: true
    }
  })

  // 2. 速率限制
  await server.register(rateLimit, {
    max: 100,
    timeWindow: '1 minute',
    skipOnError: true,
    addHeaders: {
      'x-ratelimit-limit': true,
      'x-ratelimit-remaining': true,
      'x-ratelimit-reset': true
    }
  })

  // 3. 请求日志（审计）
  server.addHook('onRequest', (request, reply, done) => {
    const logData = {
      method: request.method,
      url: request.url,
      ip: request.ip,
      userAgent: request.headers['user-agent'],
      timestamp: new Date().toISOString()
    }
    server.logger.info(logData, 'Incoming request')
    done()
  })
})
```

