```

```typescript
// src/dashboard/middleware/validation.ts
import Ajv from 'ajv'
import addFormats from 'ajv-formats'

const ajv = new Ajv({ allErrors: true })
addFormats(ajv)

// 验证 Schema
export function validateBody(schema: object) {
  return async (request: any, reply: any) => {
    const validate = ajv.compile(schema)
    const valid = validate(request.body)

    if (!valid) {
      reply.code(400).send({
        success: false,
        error: {
          message: 'Validation failed',
          details: validate.errors
        }
      })
      throw new Error('Validation failed')
    }
  }
}

// 使用示例
const createIterationSchema = {
  type: 'object',
  required: ['requirement'],
  properties: {
    requirement: {
      type: 'string',
      minLength: 10,
      maxLength: 10000,
      pattern: '^[\\s\\S]*$' // 允许所有字符
    },
    iterationNumber: {
      type: 'number',
      minimum: 1,
      maximum: 999999
    }
  }
}

// 在路由中使用
fastify.post('/api/iterations', {
  preHandler: validateBody(createIterationSchema)
}, async (request, reply) => {
  // 处理请求
})
```

