#### **任务 4: AutoIterationEngine 与 Dashboard 集成**
**工作量**: 2 天 | **文件**: `src/auto-iteration.ts`

```typescript
// src/auto-iteration.ts

import { getServices } from './dashboard/server'

export class AutoIterationEngine {
  private iterationService?: any
  private realtimeService?: any

  async start() {
    // 初始化服务
    const services = getServices()
    this.iterationService = services.iterationService
    this.realtimeService = services.realtimeService

    while (this.running && this.shouldContinue()) {
      const iterationNum = this.iterationCount + 1

      try {
        // 1. 创建迭代记录
        const iteration = await this.iterationService.create({
          iterationNumber: iterationNum,
          status: 'running',
          requirement: this.requirement || '',
          startedAt: new Date()
        })

        // 2. 广播迭代开始
        await this.realtimeService.broadcast({
          event: 'iteration.started',
          data: {
            iterationId: iteration.id,
            iterationNumber: iterationNum,
            timestamp: new Date()
          }
        })

        // 3. 执行产品经理分析
        await this.notifyProgress('product_manager', 0, '开始需求分析...')
        const pmResult = await this.productManager.executeAndCollect(
          `分析以下需求：\n${this.requirement}`
        )

        await this.notifyProgress('product_manager', 100, '需求分析完成')
        await this.saveAgentResult('product_manager', pmResult)

        // 4. 执行其他 Agent...
        // （类似的模式）

        // 5. 更新迭代状态
        await this.iterationService.update(iteration.id, {
          status: 'completed',
          completedAt: new Date()
        })

        // 6. 广播完成
        await this.realtimeService.broadcast({
          event: 'iteration.completed',
          data: { iterationId: iteration.id }
        })

      } catch (error) {
        // 错误处理
        await this.iterationService.update(iteration.id, {
          status: 'failed',
          error: String(error)
        })
      }
    }
  }

  async notifyProgress(agentType: string, progress: number, message: string) {
    await this.realtimeService.broadcast({
      event: 'iteration.progress',
      data: {
        agentType,
        progress,
        message,
        timestamp: new Date()
      }
    })
  }

  async saveAgentResult(agentType: string, result: string) {
    await this.realtimeService.broadcast({
      event: 'agent.result',
      data: {
        agentType,
        result,
        timestamp: new Date()
      }
    })
  }
}
```

