  subscribe(client: WebSocket, channel: string) {
    // 实现客户端订阅特定频道的逻辑
    if (!this.subscriptions.has(channel)) {
      this.subscriptions.set(channel, new Set());
    }
    this.subscriptions.get(channel)!.add(client);

    // 发送订阅成功确认
