```typescript
// 1. 在 BaseAgent 中添加重试逻辑
class BaseAgent {
  async executeWithRetry(
    prompt: string,
    maxRetries = 3,
    backoffMs = 1000
  ): Promise<string> {
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        return await this.executeAndCollect(prompt);
      } catch (error) {
        if (attempt === maxRetries) throw error;

        // 指数退避
        const delay = backoffMs * Math.pow(2, attempt - 1);
        console.log(`⚠️ 第 ${attempt} 次失败,${delay}ms 后重试...`);
        await this.sleep(delay);
      }
    }
    throw new Error('Max retries exceeded');
  }
}

// 2. 在 AutoIterationEngine 中添加降级策略
class AutoIterationEngine {
  async runIterationWithFallback() {
    try {
      await this.runIteration();
    } catch (error) {
      console.error('❌ 迭代失败:', error);

      // 降级: 仅提交部分结果
      if (this.config.autoCommit) {
        await this.gitCommit('partial: ' + error.message);
      }

      // 记录失败
      this.history.push({
        iteration: this.iterationCount,
        task: 'unknown',
        status: 'failed',
        message: String(error),
        timestamp: new Date(),
      });
    }
  }
}
```

