    }
  }
});

// 使用示例
logger.info({ iteration: 5, phase: 'product_manager' }, '开始分析');
```

2. **日志写入数据库**
```typescript
class LogService {
  async saveLog(entry: LogEntry) {
    await db.logs.create({
      data: {
        timestamp: entry.timestamp,
        level: entry.level,
        message: entry.message,
        context: entry.context
      }
    });
  }
}
```

3. **日志搜索 API**
```typescript
fastify.get('/logs', async (request, reply) => {
  const { level, startDate, endDate, keyword } = request.query;
  const logs = await logService.search({
    level,
    startDate,
    endDate,
    keyword
  });
  return reply.send(logs);
});
```

